import { useState, useEffect, useRef } from '@wordpress/element';

export default function TimePickerField({ label, value, onChange, interval = 15, startHour = 6, endHour = 23 }) {
    const [open, setOpen] = useState(false);
    const ref = useRef(null);

    const parseValue = (val) => {
        if (!val) return { hour: startHour, min: 0 };
        const [h, m] = val.split(':').map(Number);
        return { hour: h, min: m };
    };

    const { hour: selHour, min: selMin } = parseValue(value);

    const selectHour = (h) => {
        // Använd det nuvarande valda värdet eller fallback till 00
        const m = selMin.toString().padStart(2, '0');
        const hStr = h.toString().padStart(2, '0');
        onChange(`${hStr}:${m}`);
    };

    const selectMin = (m) => {
        // Använd det nuvarande valda värdet eller fallback till 00
        const h = selHour.toString().padStart(2, '0');
        const mStr = m.toString().padStart(2, '0');
        onChange(`${h}:${mStr}`);
    };

    const hours = [];
    for (let h = startHour; h <= endHour; h++) hours.push(h);

    const minutes = [];
    for (let m = 0; m < 60; m += interval) minutes.push(m);

    useEffect(() => {
        const handleClick = (e) => {
            if (ref.current && !ref.current.contains(e.target)) setOpen(false);
        };
        document.addEventListener('mousedown', handleClick);
        return () => document.removeEventListener('mousedown', handleClick);
    }, []);

    return (
        <div ref={ref} style={s.wrap}>
            {label && <div style={s.label}>{label}</div>}

            <button style={s.field} onClick={() => setOpen(!open)} type="button" aria-haspopup="true" aria-expanded={open}>
                <span style={s.fieldValue}>{value || '--:--'}</span>
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" aria-hidden="true">
                    <circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/>
                </svg>
            </button>

            {open && (
                <div style={s.popover} role="dialog" aria-label="Välj tid">

                    {/* Timmar */}
                    <div style={s.hoursScroll}>
                        {hours.map((h) => (
                            <button
                                key={h}
                                type="button"
                                style={{ ...s.hourBtn, ...(h === selHour ? s.hourBtnActive : {}) }}
                                onClick={() => selectHour(h)}
                            >
                                {h.toString().padStart(2, '0')}
                            </button>
                        ))}
                    </div>

                    {/* Minuter */}
                    <div style={s.minutesWrap}>
                        <div style={s.minutesLabel}>Minuter</div>
                        <div style={s.minuteGrid}>
                            {minutes.map((m) => (
                                <button
                                    key={m}
                                    type="button"
                                    style={{ ...s.minBtn, ...(m === selMin ? s.minBtnActive : {}) }}
                                    onClick={() => selectMin(m)}
                                >
                                    {m.toString().padStart(2, '0')}
                                </button>
                            ))}
                        </div>
                    </div>

                    {/* Bekräfta */}
                    <div style={s.footer}>
                        <button type="button" style={s.confirmBtn} onClick={() => setOpen(false)}>
                            Välj {value}
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
}

const s = {
    wrap: {
        position: 'relative',
        display: 'inline-block',
        minWidth: 140,
    },
    label: {
        fontSize: 13,
        fontWeight: 500,
        color: '#1d2327',
        marginBottom: 6,
        display: 'block',
    },
    field: {
        width: '100%',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        padding: '9px 12px',
        background: '#fff',
        border: '1px solid #8c8f94',
        borderRadius: 2,
        fontSize: 15,
        fontWeight: 500,
        color: '#1d2327',
        cursor: 'pointer',
        gap: 8,
    },
    fieldValue: {
        flex: 1,
        textAlign: 'left',
    },
    popover: {
        position: 'absolute',
        top: 'calc(100% + 4px)',
        left: 0,
        zIndex: 9999,
        background: '#fff',
        border: '1px solid #dcdcde',
        borderRadius: 8,
        boxShadow: '0 4px 16px rgba(0,0,0,0.08)',
        minWidth: 220,
        overflow: 'hidden',
    },
    hoursScroll: {
        display: 'flex',
        overflowX: 'auto',
        borderBottom: '1px solid #f0f0f1',
        scrollbarWidth: 'none',
    },
    hourBtn: {
        flexShrink: 0,
        padding: '9px 10px',
        fontSize: 13,
        fontWeight: 500,
        background: 'transparent',
        border: 'none',
        cursor: 'pointer',
        color: '#646970',
        transition: 'background 0.1s',
        minWidth: 36,
        textAlign: 'center',
    },
    hourBtnActive: {
        background: '#f0f6fc',
        color: '#2271b1',
    },
    minutesWrap: {
        padding: '10px 12px',
    },
    minutesLabel: {
        fontSize: 12,
        color: '#646970',
        marginBottom: 8,
    },
    minuteGrid: {
        display: 'flex',
        flexWrap: 'wrap',
        gap: 6,
    },
    minBtn: {
        padding: '6px 10px',
        fontSize: 13,
        fontWeight: 500,
        background: 'transparent',
        border: '1px solid #dcdcde',
        borderRadius: 4,
        cursor: 'pointer',
        color: '#1d2327',
        minWidth: 52,
        textAlign: 'center',
    },
    minBtnActive: {
        background: '#f0f6fc',
        border: '1px solid #2271b1',
        color: '#2271b1',
    },
    footer: {
        padding: '8px 12px',
        borderTop: '1px solid #f0f0f1',
        display: 'flex',
        justifyContent: 'flex-end',
    },
    confirmBtn: {
        fontSize: 13,
        padding: '6px 14px',
        borderRadius: 4,
        border: '1px solid #2271b1',
        background: '#f0f6fc',
        color: '#2271b1',
        cursor: 'pointer',
        fontWeight: 500,
    },
};